<<switch>> <<grade>> {
<<case>> <<"A">>:
<<gradeValue>> = 4.0;
<<break>>;
<<case>> <<"B">>:
<<gradeValue>> = 3.0;
<<break>>;
<<case>> <<"C">>:
<<gradeValue>> = 2.0;
<<break>>;
<<case>> <<"D">>:
